{"cmd":"echo '---system stale candidates in /private/var/folders and tmp---'; 
find /private/var/folders -maxdepth 4 -type d -path '*/T/*' -name '.TemporaryItems' -prune -o -type d -name 'T' -print 2>/dev/null | head -n 40
# old .tmp dirs under T
for d in $(find /private/var/folders -maxdepth 3 -type d -name 'T' 2>/dev/null); do
  find "$d" -maxdepth 1 -type d -mtime +7 \( -name 'mac-*' -o -name 'mac_cleanup*' -o -name 'mac_48h*' -o -name 'codex*' -o -name 'eei*' -o -name 'adp*' -o -name 'playwright*' -o -name 'node-compile-cache' -o -name 'pytest-of-linzezhang' -o -name 'F3CNN' -o -name 'moomoo*' \) 2>/dev/null | head -n 20;
done","workdir":"[REDACTED_LOCAL_PATH]","max_output_tokens":12000}

